export const WEEK1_CONTENT: DocParagraph[] = [
  { style: 'Normal', text: 'WEEK 1' },
  { style: 'Normal', text: 'WELCOME AND ORIENTATION' },
  { style: 'Normal', text: 'Introductory Session — Modified Rhythm' },
  { style: 'Normal', text: 'WHERE YOU ARE IN THE ARC' },
  { style: 'Normal', text: 'This is the first session of a fifty-two-week journey — but it is also the first session of a thirteen-week quarter. That distinction matters, and you will explain it today.' },
  { style: 'Normal', text: 'Book 1 — In The Quiet — covers the Foundation Quarter: Understanding and Acknowledging. Weeks 1–4 name grief and establish safety. Weeks 5–9 explore its dimensions. Weeks 10–13 begin the first integration work. Today you are laying the ground that everything else stands on.' },
  { style: 'Normal', text: 'Your job today is not to teach. It is not to cover content. It is to make this room safe enough, warm enough, and clear enough that people come back next week. If they leave feeling welcomed, understood, and clear about what to expect — you have succeeded.' },
  { style: 'Normal', text: 'FACILITATOR: This session uses a modified rhythm. Week 1 is an orientation, not a full content session. You are building the container. The deep work begins in Week 2. The thesis that governs everything you do in this room — today and for the next fifty-two weeks — is this: hope in despair is love seeking for love itself. You do not say those words to participants. You hold them. They will feel it in how you receive what they bring.' },
  { style: 'Normal', text: 'SESSION AT A GLANCE	90–100 min' },
  { style: 'Normal', text: 'Opening & Grounding	10 min	[IN SESSION]' },
  { style: 'Normal', text: 'Welcome & The Heart of Live and Grieve	20–25 min	[IN SESSION]' },
  { style: 'Normal', text: 'The Research — What Grief Actually Does	10–15 min	[IN SESSION]' },
  { style: 'Normal', text: 'Group Agreements	10 min	[IN SESSION]' },
  { style: 'Normal', text: 'Introductions & First Share	15 min	[IN SESSION]' },
  { style: 'Normal', text: 'Your Workbook — A Page-by-Page Walkthrough	10–15 min	[IN SESSION]' },
  { style: 'Normal', text: 'Between-Session Work & What Comes Next	5–10 min	[BETWEEN SESSIONS]' },
  { style: 'Normal', text: 'Closing Affirmation & Check-Out	5–10 min	[IN SESSION]' },
  { style: 'Normal', text: 'BEFORE THE SESSION — FACILITATOR PREPARATION' },
  { style: 'Normal', text: 'Room Checklist' },
  { style: 'Normal', text: 'FACILITATOR: Complete this before any participant arrives.' },
  { style: 'Normal', text: '□  Chairs arranged in a circle or semicircle. No tables between you and participants. You sit in the circle, not outside it. Same height as everyone else.' },
  { style: 'Normal', text: '□  A workbook placed on every chair. Participants find it waiting — they do not have to ask for it.' },
  { style: 'Normal', text: '□  Tissues available in at least two locations within the circle. Visible but not centered. You are prepared, not expecting.' },
  { style: 'Normal', text: '□  Water available.' },
  { style: 'Normal', text: '□  The five Group Agreements written on a whiteboard, flip chart, or poster — ready to be revealed, not already visible. You will introduce them together.' },
  { style: 'Normal', text: '□  Door visible to everyone from their seat. No one should feel trapped.' },
  { style: 'Normal', text: '□  Temperature comfortable. Check before people arrive.' },
  { style: 'Normal', text: '□  Crisis resource card at your seat: 988, Crisis Text Line (741741), SAMHSA (1-800-662-4357), NAMI (1-800-950-6264), 911.' },
  { style: 'Normal', text: '□  Your Facilitator Reflection Log — physical copy — at your seat.' },
  { style: 'Normal', text: '□  You have read the full WB1 Week 1 content. You know what participants will find when they open their workbook at home.' },
  { style: 'Normal', text: 'Inner Preparation' },
  { style: 'Normal', text: 'FACILITATOR REFLECTION:' },
  { style: 'Normal', text: '1.  What is your own emotional state right now? Name it specifically. Not “fine.” Not “ready.”' },
  { style: 'Normal', text: '2.  Have you read the Opening Reflection aloud — not silently — at least once? The words land differently spoken.' },
  { style: 'Normal', text: '3.  What are you afraid of? First sessions carry fear for facilitators too. Name it. It loses power when you look at it.' },
  { style: 'Normal', text: '4.  What is your intention for this session? Not what you will cover. What you will hold.' },
  { style: 'Normal', text: 'FACILITATOR: If a participant arrives in visible crisis BEFORE the session — shaking, hyperventilating, unable to speak — do not start the session. Go to them. Sit with them. Offer water. Ask: “Are you safe right now?” If they are not, call 988 together. If they are, ask: “Would you like to stay, or would you like me to walk you to your car?” Either answer is correct. The group can wait. Safety comes first.' },
  { style: 'Normal', text: 'OPENING & GROUNDING' },
  { style: 'Normal', text: '10 minutes' },
  { style: 'Normal', text: '[IN SESSION]' },
  { style: 'Normal', text: 'FACILITATOR: Read this slowly. Let the pauses be real, not performed. Breathe with them. Your calm is their first experience of safety. You are not performing stillness. You are being still.' },
  { style: 'Normal', text: '[WB1 VERBATIM — Opening Reflection]' },
  { style: 'Normal', text: 'SAY: “Welcome. Thank you for being here. Before we begin, I want to say something that matters: being in this room took courage. Whatever brought you here — whatever you are carrying — the fact that you showed up today says something about who you are and what you believe is possible. We are going to start the way we will start every session for the next year. With a moment of stillness. Find a comfortable position. If it feels right, close your eyes. If not, let your gaze rest somewhere soft — the floor, your hands, the space in front of you. Place one hand on your heart. Feel the weight of your own hand. Feel the rhythm underneath. Take three deep breaths. Not forced. Just slow, and deliberate, and yours.”' },
  { style: 'Normal', text: 'FACILITATOR: Pause. Breathe with them. Count silently — at least five full seconds between each breath.' },
  { style: 'Normal', text: '[WB1 VERBATIM — Opening Reflection, cont.]' },
  { style: 'Normal', text: 'SAY: “As you sit here at the beginning of this journey, acknowledge that you have taken an important step. There is no roadmap for grief that works for everyone. But there are companions and guides along the way. This workbook is one such companion. This group is another. Your courage in beginning this process is already a profound act of both honoring your loss and honoring your life. Breathe deeply once more. And when you are ready, open your eyes and continue.”' },
  { style: 'Normal', text: 'FACILITATOR: Allow 30–60 seconds of silence after finishing. Do not speak first. Let the room settle.' },
  { style: 'Normal', text: 'SAY: “That opening — the hand on the heart, the three breaths, the moment of stillness — will open every session we have together. Same beginning, every week. You will come to rely on it. The consistency is itself a kind of care.”' },
  { style: 'Normal', text: 'WATCH FOR' },
  { style: 'Normal', text: '•  The person who cannot close their eyes. Possible trauma history. The instruction says “if it feels right” — honor that. Do not comment.' },
  { style: 'Normal', text: '•  Crying before you finish. Let it happen. Do not stop reading. Your steady voice holds them.' },
  { style: 'Normal', text: '•  Late arrival. Welcome with a nod. Do not restart.' },
  { style: 'Normal', text: 'WELCOME & THE HEART OF LIVE AND GRIEVE' },
  { style: 'Normal', text: '20–25 minutes' },
  { style: 'Normal', text: '[IN SESSION]' },
  { style: 'Normal', text: 'FACILITATOR: This is the most important section of Session 1. You are not delivering information. You are connecting every person in this room to the reason this program exists. Speak from this — slowly, honestly. If your voice carries emotion, let it. This is grief work. Emotion belongs here. The three convictions that run through every session of every week of all 52 weeks are woven into what follows: grief and living are not opposites; the bond continues; every person’s grief is legitimate. You do not name them as “convictions.” You speak them as truth.' },
  { style: 'Normal', text: 'What This Program Is' },
  { style: 'Normal', text: 'SAY: “My name is [your name], and I am your facilitator for this program. Live and Grieve is a grief education program. Not therapy. Not counseling. Not a place where someone tells you how to feel or when to stop feeling it. It is a place where your grief is welcome for as long as it needs to be here. This program was built by two people who lost people they loved — and who could not find what they needed. So they built it. They did not come to grief research through a classroom. They came to research through grief — through their own, and through watching it move through the people they loved. By the time they found the research literature, they had already lived most of what it described. The Dual Process Model did not teach them that grief moves back and forth. It gave them the word for something they had already been doing without knowing what to call it. Continuing Bonds Theory did not teach them that love outlasts loss. They already knew that. The research came later, and it mattered — it gave structure to intuition and language to experience. But the experience came first. It always does. They built it because what they needed did not exist. And they believed no one should have to search the way they searched. They believe that grief and living are not opposites — that you can carry your loss and still engage with life, and that both are happening in you right now, wherever you are, whether anyone has named it or not. And they built it on the integrated architecture of five research frameworks and the philosophical influence of grief companion Alan Wolfelt — the life’s work of researchers who spent decades studying what grief actually does to human beings, joined to the companioning stance that shaped how we hold this room. Live and Grieve is the first peer grief education program built on this integrated architecture. That matters, because grief is not one thing. It is many things happening at once. A program that only addresses one dimension of grief leaves you holding the rest alone. This program does not do that. It holds all of it. For a full year.”' },
  { style: 'Normal', text: 'What This Room Is' },
  { style: 'Normal', text: 'SAY: “This room is a container. That word matters. A container holds things safely. It does not fix them. It does not rush them. It holds them. Every week, you will come into this room and find the same structure waiting for you. We will open the same way — hand on heart, three breaths. We will close the same way — an affirmation read together, a one-word check-out. In between, you will engage with your grief and with your life, because this program believes those are not opposites. I want to pause on that word — AND. The name of this program is Live AND Grieve. Not live after you grieve. Not grieve until you can live again. Both. At the same time. That small word carries the entire philosophy of what we do here. You are already doing it. You are grieving AND you are still here. You are carrying loss AND you are still breathing. This program gives that reality structure and company. You do not have to choose between grief and life. You never did.”' },
  { style: 'Normal', text: 'How the Program Is Structured' },
  { style: 'Normal', text: 'SAY: “Live and Grieve is a fifty-two-week program, but it is built in four quarters — four books of thirteen weeks each. Each quarter has its own theme, its own workbook, and its own focus. Book 1 — In The Quiet — is about understanding and acknowledging. This is where we are now. We name the grief. We learn what it is. We begin to sit with it honestly. Book 2 — Through The Weight — is about exploring and processing. We go deeper. Book 3 — Toward the Light — is about integrating and adapting. We begin to find how grief and life fit together. Book 4 — With the Memory — is about growing and connecting. We carry the love forward. Here is what I want you to know: these four quarters can be done in any order. If someone joins us in Book 2, they are not behind. If someone starts with Book 4 and then comes back for Book 1, that is valid. Each quarter is complete on its own. Each workbook stands alone. There is no wrong door into this program.”' },
  { style: 'Normal', text: 'FACILITATOR: Pause here. Let this land. For many participants, the idea that they are not “behind” is the first relief they have felt in months.' },
  { style: 'Normal', text: 'If You Miss a Session' },
  { style: 'Normal', text: 'SAY: “Life happens. Grief happens. There will be weeks when you cannot be here. I want you to hear this clearly: if you miss a session, you have not fallen behind. You have not failed. You have not lost your place. When you come back, we will be glad to see you. Your chair will be here. Your workbook will pick up wherever you left off. The group will welcome you back without question. This program is not a class where you miss a lecture and cannot catch up. It is a circle. The circle does not close when you step away. It holds your space until you return.”' },
  { style: 'Normal', text: 'FACILITATOR: This is particularly important for participants in acute grief. Some will miss sessions because getting out of bed is too much. Normalizing absence removes the shame that keeps people from returning.' },
  { style: 'Normal', text: 'What I Am and What I Am Not' },
  { style: 'Normal', text: 'SAY: “I am your facilitator. I am here to walk beside you through this. Not ahead of you. Not above you. Beside you. I am not a therapist. I am not here to diagnose you, treat you, or tell you what your grief should look like. I am here to hold this space, to keep it safe, to make sure every person in this circle is seen and heard. I am trained in this program and in trauma-informed facilitation. That means I understand how grief moves through a person, and I know how to hold a room where that movement is happening. But I am not the expert on your grief. You are. You have been living it. You know more about your grief than any framework or any facilitator ever will. What I offer is structure, consistency, and presence. What you bring is everything else. If at any point your grief feels unmanageable — if you are in crisis, if you are having thoughts of harming yourself — I will help you connect with professional support. That is not a failure of this program. That is this program working exactly as it should. Your workbook has crisis resources in the back — 988 is available 24/7 by call or text. We know our boundaries, and we honor them.”' },
  { style: 'Normal', text: 'THE RESEARCH' },
  { style: 'Normal', text: 'WHAT GRIEF ACTUALLY DOES — 10–15 minutes' },
  { style: 'Normal', text: '[IN SESSION]' },
  { style: 'Normal', text: 'FACILITATOR: Do not skip this section. Participants need to understand the research foundation BEFORE they go home to write “My Grief Story.” The framework gives their experience a name. For many, this will be the first time anyone has told them that what they are going through is not pathology — it is the process working correctly. Deliver this in your own words. Accessible language only.' },
  { style: 'Normal', text: 'Grief Is Bigger Than You Think' },
  { style: 'Normal', text: 'SAY: “Before we go further, I want to talk about what grief actually is — because most of us grew up with a version of it that is incomplete. We were taught that grief is about death. It is — but it is also about the end of a relationship, the loss of health, the loss of a role, the loss of who you thought you would be. Anything that was important and is no longer present. If you have lost something that mattered, you are grieving. That is not dramatic. That is accurate. And grief does not just live in your emotions. It shows up in your body — fatigue, tension, chest tightness, that feeling of being ‘off’ that you cannot explain. It shows up in your thinking — fog, forgetfulness, the sense that the world has become unfamiliar. It shows up in your behavior — withdrawal, restlessness, searching. And it shows up in your spirit — questioning what you believe, searching for meaning. All of that is grief. Not just the crying. All of it. And all of it belongs in this room.”' },
  { style: 'Normal', text: 'What the Research Says' },
  { style: 'Normal', text: 'SAY: “This program is built on five research frameworks and the philosophical influence of grief companion Alan Wolfelt — bodies of research and stance that have studied and held grief for decades. I am not going to lecture you on them. But I want you to hear what they found, because it matters for what you are going through right now. The first is called the Dual Process Model. Researchers named Margaret Stroebe and Henk Schut studied how people actually grieve — not how textbooks say they should grieve, but how they actually do it. And what they found is this: grief does not move in stages. It does not go in a straight line. It moves back and forth. Some days you are in the grief — fully, completely. The wave hits and you are inside it. Other days you are functioning. You go to work. You cook dinner. You laugh at something and then feel guilty for laughing. Both of those days are grief working correctly. You oscillate between facing the loss and engaging with life. Back and forth. That movement is not failure. It is not backsliding. It is the process. And every session in this program carries both sides — a Grief Processing activity that faces the loss, and a Living Forward activity that turns toward life. Not because we are rushing you. Because both are always present. The second thing the research tells us comes from a man named William Worden. He said grief is not something that happens to you. It is something you do. It has tasks — accepting the reality of the loss, processing the pain, adjusting to a world that has changed, and finding a way to carry the love forward. Tasks. Not stages. Things you actively do. That is what this workbook is for — it gives you the space to do that work. The third thing — and for many people this is the one that matters most — comes from researchers named Klass, Silverman, and Nickman. For decades, the grief field told people that healthy grieving meant letting go. Severing the bond. Moving on. These researchers challenged that. They found that the bond does not break. It changes form. The love does not end. It releases into something different. You do not have to let go of the person you lost. You never have to let go. You carry them with you. This program is built on that belief. The fourth is about meaning — the work of Robert Neimeyer. He found that meaning can emerge from loss without requiring that the loss was good or necessary. And sometimes meaning does not come at all, and carrying that absence is its own kind of work. The fifth is self-compassion — Kristin Neff’s research. Learning to hold yourself with enough gentleness to look honestly at what you are carrying. For many people in this program, that practice becomes the floor everything else stands on. And alongside these five research frameworks is the companioning stance — the work of Alan Wolfelt. Wolfelt is not a research framework but a philosophical influence on this program: he shaped the most important decision we made in building it: how to position me. I am not here as an expert with answers. I am here to hold the room while you do your own work — a steady light beside the weight you came in with. That distinction changes everything.”' },
  { style: 'Normal', text: 'FACILITATOR: Let this sit. Do not rush into the next section. If someone is visibly moved, acknowledge it: “What you are feeling right now is real. That is what this program is for.”' },
  { style: 'Normal', text: 'SAY: “Those five research frameworks and the Wolfelt companioning influence are the foundation of everything in your workbook, everything in this room, and everything we will do together for the next year. You do not need to memorize them. You will live them.”' },
  { style: 'Normal', text: 'GROUP AGREEMENTS' },
  { style: 'Normal', text: '10 minutes' },
  { style: 'Normal', text: '[IN SESSION]' },
  { style: 'Normal', text: 'FACILITATOR: These are not rules you read to them. They are agreements the group makes together. Introduce each one. Explain why it matters. Reveal the written agreements on the board or flip chart as you go. These agreements will be referenced throughout all 52 weeks — in Week 5 (sharing boundaries), Week 8 (no-fixing during trigger work), Week 10 (right to pass during difficult emotions), and Week 13 (reflecting on what they made possible).' },
  { style: 'Normal', text: 'SAY: “Before we go any further, we need to build the foundation of this room together. These are not rules. They are agreements — promises we make to each other about how we will be in this space.”' },
  { style: 'Normal', text: 'Agreement 1: Confidentiality' },
  { style: 'Normal', text: 'SAY: “What is shared in this room stays in this room. You may talk about your own experience outside this group. You may not share anyone else’s story, words, or identity. This is non-negotiable. Without it, nothing else works.”' },
  { style: 'Normal', text: 'Agreement 2: The Right to Pass' },
  { style: 'Normal', text: 'SAY: “You always have the right to pass. On any question. On any activity. On any share. Passing is not a failure. It is self-care. No one will ask you why. No one will pressure you to change your mind.”' },
  { style: 'Normal', text: 'Agreement 3: No Fixing' },
  { style: 'Normal', text: 'SAY: “When someone shares their grief in this room, our job is to witness it — not to fix it. No advice. No ‘have you tried…’ No ‘at least…’ No silver linings. Grief does not need to be solved. It needs to be held. We hold it by listening.”' },
  { style: 'Normal', text: 'Agreement 4: No Comparing' },
  { style: 'Normal', text: 'SAY: “Every loss in this room is real. We do not rank grief. We do not say ‘at least you had them for twenty years’ or ‘at least it wasn’t sudden.’ There is no hierarchy of pain here. Your grief is yours. It is enough to qualify you for this room.”' },
  { style: 'Normal', text: 'Agreement 5: Presence Over Performance' },
  { style: 'Normal', text: 'SAY: “You do not have to perform recovery in this room. You do not have to show progress. You do not have to be brave, or strong, or okay. You just have to be here. However you show up today — that is enough.”' },
  { style: 'Normal', text: 'SAY: “Can we agree to these together?”' },
  { style: 'Normal', text: 'FACILITATOR: Pause for verbal or visible affirmation from each participant. If someone hesitates: “Take whatever time you need with these. They will be here every week.” Write all five visibly. They stay posted for every session through all 13 weeks.' },
  { style: 'Normal', text: 'INTRODUCTIONS & FIRST SHARE' },
  { style: 'Normal', text: '15 minutes' },
  { style: 'Normal', text: '[IN SESSION]' },
  { style: 'Normal', text: 'FACILITATOR: This is NOT the group discussion from a standard session. You are asking for names and one sentence. Not grief stories. The deep sharing begins in Week 2. The bar is deliberately low.' },
  { style: 'Normal', text: 'SAY: “I would like to go around the circle and hear from each of you. Just your name and one sentence — whatever feels right. It could be what brought you here. It could be one word about how you are feeling. It could be the name of the person you lost, if you are ready to say it. There is no wrong answer. I will go first.”' },
  { style: 'Normal', text: 'FACILITATOR: Share your name and one honest sentence. Model vulnerability briefly — under 30 seconds. Then go around. After each person, pause. Make eye contact. Say: “Thank you, [name].” Nothing more. Do not reflect, interpret, or connect their words to anyone else’s.' },
  { style: 'Normal', text: 'SAY: “Thank you — every one of you. What just happened is not small. You showed up. You said your name. You let yourself be seen. That is how this begins.”' },
  { style: 'Normal', text: 'WATCH FOR' },
  { style: 'Normal', text: '•  Someone in acute grief who cannot speak. “Your presence is your introduction. Thank you for being here.”' },
  { style: 'Normal', text: '•  Someone who over-shares. Gently: “I want to honor everything you are carrying. We will have so much time for your story. For right now, can you give me one sentence?”' },
  { style: 'Normal', text: '•  Someone who uses humor to deflect. Receive it warmly. Do not call it out.' },
  { style: 'Normal', text: 'YOUR WORKBOOK' },
  { style: 'Normal', text: 'A PAGE-BY-PAGE WALKTHROUGH — 10–15 minutes' },
  { style: 'Normal', text: '[IN SESSION]' },
  { style: 'Normal', text: 'FACILITATOR: Have everyone pick up their workbook. This is a physical walkthrough. They touch the pages, see the colors, understand the structure. Familiarity reduces anxiety. Do not rush this. If workbooks didn’t arrive or a participant forgot theirs, you can speak the prompts aloud and direct them to write in a notebook — the content in this session guide is sufficient to run without the workbook present.' },
  { style: 'Normal', text: 'SAY: “I want you to pick up your workbook. This book is your companion for the next thirteen weeks. It is yours — write in it, mark it up, fold the corners. It is not precious. It is practical. It goes where you go. Let’s walk through it together.”' },
  { style: 'Normal', text: 'The Weekly Structure' },
  { style: 'Normal', text: 'SAY: “Open to Week 1. Every week follows the same structure. Let me show you what you will find. At the top: an Opening Reflection. That is what we just did together — the hand on the heart, the breathing. It is printed here so you can return to it any time, even at home, even alone. Below that: the Educational Component. This is the week’s theme explained in plain, honest language. It is not a textbook. It is the research translated into something you can feel, not just read. Then you will see a green callout box — the Key Concept. This is the one idea from the research that anchors the week. One thing to carry.”' },
  { style: 'Normal', text: 'The Three Activity Colors' },
  { style: 'Normal', text: 'SAY: “Now look at the activities. You will notice three different colors. These colors are not decoration. They mean something. Pink is for Grief Processing. [Hold up the page or point.] These activities face the loss directly. They ask you to look at your grief — to name it, to write about it, to sit with it. The pink says: this is tender ground. You are allowed to be here. Blue is for Living Forward. [Point to the blue section.] These activities turn toward life — not away from grief, but alongside it. Setting intentions. Building connections. Finding what is still possible. The blue says: there is still a world out here, and you are still in it. Lavender is for Self-Care. [Point to the lavender section.] These activities are about caring for yourself through the process. Body, mind, spirit. The lavender says: you deserve the same tenderness you would give someone you love. Every week. Pink, blue, lavender. Grief, life, self. You will start to recognize the rhythm just by the colors.”' },
  { style: 'Normal', text: 'The Write-In Areas' },
  { style: 'Normal', text: 'SAY: “Inside each activity you will see write-in areas — boxes with lines. Some have prompts. Some are open. This is where you do the work. You write. Nobody else reads it unless you choose to share. This workbook is private. It belongs to you.”' },
  { style: 'Normal', text: 'Journal Prompts, Affirmation, Gratitude, Tracker' },
  { style: 'Normal', text: 'SAY: “After the three activities, you will find four more elements. They are the same every week. Journal Prompts — questions for deeper reflection. Do one, do all of them, or skip them entirely. They are invitations, not assignments. A Weekly Affirmation — a grounding statement to carry with you. I will read it aloud at the close of every session, and it is here for you to return to during the week whenever you need it. A Gratitude Practice — one line per day, seven days. Even amid grief, noticing one small thing you are grateful for can provide balance. This is not toxic positivity. It is honest noticing. One thing. That is all. And a Weekly Progress Tracker — four dimensions, a simple 1-to-5 scale. Grief intensity, connection to others, self-care, hope. You circle where you are. No right answers. This is not a test. It is a mirror. Over thirteen weeks, you will see patterns you cannot see in the moment. And at the end of each week, you will find a closing statement. A few lines that hold what the week was about. You can read it as a bookend — a way of putting the week’s work down before the next one begins.”' },
  { style: 'Normal', text: 'Resources' },
  { style: 'Normal', text: 'SAY: “Turn to the back of your workbook. You will find a Resources section with crisis support numbers — 988, Crisis Text Line, SAMHSA. Grief organizations. Professional referral guidance. These are here for the moments when this program is not enough, and that is okay. You also have the full References — the five research frameworks and the Wolfelt companioning philosophical influence and the work behind them. An About section that tells the story of the program and the four-book series. And the program’s website — tripillarstudio.com — where you will find additional resources, information about the program, and a community of people walking this same path. This workbook has everything you need. It is complete.”' },
  { style: 'Normal', text: 'BETWEEN-SESSION WORK & WHAT COMES NEXT' },
  { style: 'Normal', text: '5–10 minutes' },
  { style: 'Normal', text: '[BETWEEN SESSIONS]' },
  { style: 'Normal', text: 'SAY: “Before we close, I want to walk you through what to do this week between now and our next session. Three things. None of them are difficult. All of them matter. First: read the Educational Component for Week 1. It is in your workbook — one page. It covers what we just talked about: what grief is, how it moves back and forth, why that movement is not failure. Reading it at home will deepen what you heard today. Second: begin the Grief Processing Activity — ‘My Grief Story.’ This is the pink section. Turn to it now.”' },
  { style: 'Normal', text: 'FACILITATOR: Wait until everyone has found the page.' },
  { style: 'Normal', text: 'SAY: “This activity asks you to begin writing about your loss. You will see prompts: Who you lost. When it happened. The circumstances surrounding the loss. And then deeper questions — what the first days were like, how your grief has changed, where you are now. Write as much or as little as feels right. If all you can write is a name and a date, that is enough. If the words pour out, let them. There is no minimum and no maximum. This is your story. And if you do not finish it — that is fine. If you open the page and close it again — that is fine. If you show up next week with a blank workbook — you are still welcome in this room. Showing up is the work. Everything else builds from there. Do not let an incomplete page keep you from coming back. A word about pacing: do not try to do everything in one sitting. Spread the writing across the week. Give your grief room to breathe between the pages. Write a little Monday. Sit with it Tuesday. Come back Wednesday. There is no rush. The workbook will wait for you. Third: look at the Self-Care Practice — ‘Comfort Corner.’ This is the lavender section. It asks you to create a small space in your home with items that comfort your senses — something to see, hear, smell, touch, taste. Build it this week if you can. When grief arrives — and it will — your nervous system reaches for something physical before your mind catches up — having something ready is how you meet yourself there. And one more thing — tonight, before you go to bed, open to the Gratitude Practice for this week and write one thing. Just one. It does not have to be big. ‘The sun came through the window.’ ‘Someone held the door.’ ‘I made it to this room.’ One line. That is enough to start.”' },
  { style: 'Normal', text: 'FACILITATOR: Do not introduce the Living Forward Activity (“Setting Intentions”) this week. That will be introduced in the Week 2 session after participants have had the experience of writing their grief story. Loss-oriented work comes before restoration-oriented work in the opening sequence. This is deliberate.' },
  { style: 'Normal', text: 'What to Expect This Week' },
  { style: 'Normal', text: 'SAY: “I want to prepare you for what might happen between now and next week. You opened a door today. You sat in a room and let yourself be seen. You are going to go home and begin writing about your loss — maybe for the first time. That may stir things up. Grief may arrive at unexpected moments. You may feel heavier before you feel lighter. You may cry in the grocery store. You may feel nothing and worry that means something is wrong. You may feel relief and then feel guilty about the relief. All of that is normal. All of that is the grief moving, which means it is no longer stuck. If it gets hard, go to your Comfort Corner. If it gets harder than that, turn to the Resources section in the back of your workbook — 988 is there, available 24/7. If you need to reach me between sessions, [provide your preferred contact — email, phone, or program-specific channel]. You are not alone between meetings.”' },
  { style: 'Normal', text: 'What Comes Next Week' },
  { style: 'Normal', text: 'SAY: “Next week is Week 2 — The Nature of Grief. We will go deeper into what grief looks like and how it shows up in the body, the mind, and the spirit. As we walk through next week’s workbook pages together, what you wrote this week — your grief story, what you noticed, what came up — will naturally be part of the conversation. Not because I ask you to present it. Because the content connects. What you experience at home lives in the room the following week. The workbook and the group feed each other. You will feel it. So when you come back, bring your workbook. Bring whatever you wrote — or did not write. And bring yourself — however you are that day.”' },
  { style: 'Normal', text: 'CLOSING AFFIRMATION & CHECK-OUT' },
  { style: 'Normal', text: '5–10 minutes' },
  { style: 'Normal', text: '[IN SESSION]' },
  { style: 'Normal', text: 'Weekly Affirmation' },
  { style: 'Normal', text: 'FACILITATOR: Read this aloud. Slowly. This is the last thing they hear before they walk back into the world. It matters.' },
  { style: 'Normal', text: 'SAY: “I want to close with this week’s affirmation. You will find it in your workbook. I am going to read it aloud. Follow along silently, or read it with me — whatever feels right.”' },
  { style: 'Normal', text: '[WB1 VERBATIM — Affirmation]' },
  { style: 'Normal', text: 'SAY: “I honor my grief as an expression of love. I give myself permission to feel all of my emotions. Each day, I will take one small step in caring for myself while carrying my loved one in my heart.”' },
  { style: 'Normal', text: 'FACILITATOR: Pause at least five seconds. Let the words settle.' },
  { style: 'Normal', text: 'The Closing Statement' },
  { style: 'Normal', text: 'SAY: “And at the bottom of your Week 1 pages, you will find a closing statement. Let me read it to you now:”' },
  { style: 'Normal', text: '[WB1 VERBATIM — Closing Statement]' },
  { style: 'Normal', text: 'SAY: “You wrote something down. You set a direction. You built something your body can reach for when language runs out. Week 1 is not preparation for the work. Week 1 is the work. You have already begun.”' },
  { style: 'Normal', text: 'FACILITATOR: Pause. Let this land. This closing statement is printed in the workbook and read aloud in the session. Participants will find one at the end of every week. This is the bookend to the Opening Reflection — how the week closes. Establish this pattern now.' },
  { style: 'Normal', text: 'One-Word Check-Out' },
  { style: 'Normal', text: 'SAY: “We are going to close the way we will close every session — with a one-word check-out. One word that describes where you are right now. Not where you think you should be. Where you actually are. There is no wrong word. ‘Heavy’ is a word. ‘Tired’ is a word. ‘Hopeful’ is a word. ‘Here’ is a word. I will go first.”' },
  { style: 'Normal', text: 'FACILITATOR: Say your word. Go around the circle. Thank each person by name. After the last person:' },
  { style: 'Normal', text: 'SAY: “Thank you — every one of you — for what you brought into this room today. Take your workbook home. Read through Week 1. Begin writing your grief story when you are ready — gently, across the week. Build your comfort corner. Write one thing in your gratitude practice tonight. At the end of the week, open the tracker and circle where you are — just noticing, no judging. And if you want to explore more about this program, what it offers, and the community behind it — tripillarstudio.com. Everything is there. Grief is not linear. There will be ups and downs between now and next week. Be gentle with yourself. And know this: next week, this room will be here. This circle will be here. I will be here. You are not carrying this alone anymore. I will see you next week.”' },
  { style: 'Normal', text: 'AFTER THE SESSION — FACILITATOR DEBRIEF' },
  { style: 'Normal', text: 'FACILITATOR: Do not leave the building immediately. Sit with what happened. Complete your Facilitator Reflection Log — the physical document at your seat — before the details soften.' },
  { style: 'Normal', text: 'FACILITATOR REFLECTION:' },
  { style: 'Normal', text: '1.  What was the tone of the room? Not what you hoped for. What it actually was.' },
  { style: 'Normal', text: '2.  Who do you want to follow up with? Someone who seemed flooded? Someone who did not speak? Someone who left early?' },
  { style: 'Normal', text: '3.  Did every participant affirm the group agreements? If someone hesitated, note it. That is information for Week 2.' },
  { style: 'Normal', text: '4.  What did you handle well today? Name one moment.' },
  { style: 'Normal', text: '5.  What would you do differently? Not what you did wrong. What you would adjust.' },
  { style: 'Normal', text: '6.  What are you carrying from this session? Facilitators absorb grief. Name what you are holding and decide what to do with it before next week.' },
  { style: 'Normal', text: 'FACILITATOR: Week 2 moves through the workbook content on grief reactions. As you walk through the educational component together, what participants wrote in “My Grief Story” will surface naturally — the grief they named at home is the grief the content is now describing. Prepare for the possibility that some participants will arrive having written pages. Others will arrive having written nothing. Both are valid. Your job is to receive whatever they bring as it comes. The container you built today is what makes that possible. The circle has begun.' },
  { style: 'Normal', text: 'Hope in despair' },
  { style: 'Normal', text: 'is love seeking' },
  { style: 'Normal', text: 'for love itself.' },
];
